#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>

int cmp_int(const void *a, const void *b) {
    int x = *(const int *)a;
    int y = *(const int *)b;
    return (x > y) - (x < y);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char col[101];
        int n;
        scanf("%s %d", col, &n);
        int *arr = (int *)malloc(n * sizeof(int));
        for (int i = 0; i < n; ++i) {
            scanf("%d", &arr[i]);
        }
        qsort(arr, n, sizeof(int), cmp_int);
        // output sorted values
        for (int i = 0; i < n; ++i) {
            printf("%d", arr[i]);
            if (i + 1 < n) printf(" ");
        }
        printf("\n");
        // median
        double median;
        if (n % 2 == 1) median = arr[n/2];
        else median = (arr[n/2 - 1] + arr[n/2]) / 2.0;
        // mean for variance
        double sum = 0.0;
        for (int i = 0; i < n; ++i) sum += arr[i];
        double mean = sum / n;
        double var = 0.0;
        for (int i = 0; i < n; ++i) {
            double diff = arr[i] - mean;
            var += diff * diff;
        }
        var /= n;
        // mode
        // frequency map using simple array offset (values are within [-1e6,1e6])
        const int OFFSET = 1000000;
        static int freq[2000001];
        memset(freq, 0, sizeof(freq));
        int maxFreq = 0;
        int mode = INT_MAX;
        for (int i = 0; i < n; ++i) {
            int idx = arr[i] + OFFSET;
            freq[idx]++;
            if (freq[idx] > maxFreq || (freq[idx] == maxFreq && arr[i] < mode)) {
                maxFreq = freq[idx];
                mode = arr[i];
            }
        }
        printf("Median: %.1f Variance: %.1f Mode: %d\n", median, var, mode);
        free(arr);
    }
    return 0;
}

