import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            st = new StringTokenizer(br.readLine());
            String col = st.nextToken();
            int n = Integer.parseInt(st.nextToken());
            long[] a = new long[n];
            for (int i = 0; i < n; i++) {
                a[i] = Long.parseLong(br.readLine().trim());
            }
            Arrays.sort(a);
            for (int i = 0; i < n; i++) {
                if (i > 0) out.append(' ');
                out.append(a[i]);
            }
            out.append('\n');
            double median;
            if (n % 2 == 1) median = a[n/2];
            else median = (a[n/2 - 1] + a[n/2]) / 2.0;
            double sum = 0.0;
            for (long v : a) sum += v;
            double mean = sum / n;
            double var = 0.0;
            for (long v : a) {
                double d = v - mean;
                var += d * d;
            }
            var /= n;
            Map<Long,Integer> freq = new HashMap<>();
            int maxFreq = 0;
            long mode = Long.MAX_VALUE;
            for (long v : a) {
                int f = freq.getOrDefault(v, 0) + 1;
                freq.put(v, f);
                if (f > maxFreq || (f == maxFreq && v < mode)) {
                    maxFreq = f;
                    mode = v;
                }
            }
            out.append(String.format(Locale.US, "Median: %.1f Variance: %.1f Mode: %d\n", median, var, mode));
        }
        System.out.print(out.toString());
    }
}

