const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const T = Number(input[idx++]);
let output = [];
for (let t = 0; t < T; t++) {
  const [col, nStr] = input[idx++].trim().split(/\s+/);
  const n = Number(nStr);
  let arr = new Array(n);
  for (let i = 0; i < n; i++) {
    arr[i] = Number(input[idx++].trim());
  }
  arr.sort((a, b) => a - b);
  output.push(arr.join(' '));
  // median
  let median;
  if (n % 2 === 1) median = arr[Math.floor(n / 2)];
  else median = (arr[n / 2 - 1] + arr[n / 2]) / 2.0;
  // variance
  const mean = arr.reduce((s, v) => s + v, 0) / n;
  const variance = arr.reduce((s, v) => {
    const d = v - mean;
    return s + d * d;
  }, 0) / n;
  // mode
  const freq = new Map();
  let maxFreq = 0;
  let mode = Infinity;
  for (const v of arr) {
    const f = (freq.get(v) || 0) + 1;
    freq.set(v, f);
    if (f > maxFreq || (f === maxFreq && v < mode)) {
      maxFreq = f;
      mode = v;
    }
  }
  output.push(`Median: ${median.toFixed(1)} Variance: ${variance.toFixed(1)} Mode: ${mode}`);
}
console.log(output.join('\n'));
